codeBlocks.code:
cd ~/{{ws}}
rosdep update
rosdep install --from-paths src --ignore-src -r -y

cd ~/{{ws}}
colcon build --symlink-install --packages-select my_pkg
source install/setup.bash

{
  "configurations": [{
    "name": "Linux",
    "includePath": [
      "${workspaceFolder}/**",
      "/opt/ros/jazzy/include/**",
      "/home/${env:USER}/{{ws}}/install/**/include"
    ],
    "defines": [],
    "compilerPath": "/usr/bin/g++",
    "cStandard": "c17",
    "cppStandard": "c++17",
    "intelliSenseMode": "linux-gcc-x64"
  }],
  "version": 4
}

{
  "version": "0.2.0",
  "configurations": [{
    "name": "ROS: Debug my_node",
    "type": "python",
    "request": "launch",
    "program": "${workspaceFolder}/install/my_pkg/lib/my_pkg/my_node",
    "args": ["--ros-args", "-p", "rate:=10.0"],
    "console": "integratedTerminal",
    "env": {
      "PYTHONUNBUFFERED": "1"
    }
  }]
}

{
  "name": "ros2-humble-dev",
  "image": "osrf/ros:jazzy-desktop",
  "runArgs": ["--net=host", "--ipc=host", "--privileged"],
  "customizations": {
    "vscode": {
      "extensions": [
        "ms-iot.vscode-ros",
        "ms-vscode.cpptools",
        "ms-python.python",
        "ms-python.vscode-pylance"
      ]
    }
  },
  "remoteUser": "root",
  "workspaceFolder": "/workspaces/{{ws}}"
}
